/* Settings — backup, restore */
function SettingsModal({close,data,pin,restoreData}){
  const[restoreStep,setRestoreStep]=useState("idle");
  const[restoreFile,setRestoreFile]=useState(null);
  const[restorePin,setRestorePin]=useState("");
  const[restoreErr,setRestoreErr]=useState("");
  const[restoreMsg,setRestoreMsg]=useState("");
  const lb=localStorage.getItem("mm:lastBackup");
  const daysAgo=lb?Math.floor((Date.now()-new Date(lb).getTime())/86400000):null;
  const[fyMode,setFyMode]=useState(false);

  const doRestore=async()=>{
    if(!restoreFile)return;setRestoreErr("");
    try{const text=await restoreFile.text();const d=await importBackup(text,restorePin);restoreData(d);setRestoreMsg("Restored successfully! All your data is back.");setRestoreStep("done");}
    catch(e){setRestoreErr("Could not restore — wrong PIN or invalid file.");}
  };

  const fy=currentFY();const{start,end}=fyRange(fy);
  const fyTxns=data.transactions.filter(t=>t.date>=start&&t.date<=end);
  const fyInc=fyTxns.filter(t=>t.type==="income").reduce((s,t)=>s+(+t.amount),0);
  const fyExp=fyTxns.filter(t=>t.type==="expense").reduce((s,t)=>s+(+t.amount),0);

  return(<Sheet close={close} title="Settings">
    {/* Backup */}
    <div style={{background:C.bg,borderRadius:14,padding:16,marginBottom:12}}>
      <div style={{fontSize:14,fontWeight:700,marginBottom:4}}>💾 Backup</div>
      <div style={{fontSize:12,color:C.muted,marginBottom:10}}>{lb?`Last backup: ${daysAgo===0?"today":daysAgo===1?"yesterday":`${daysAgo} days ago`}`:"Never backed up"}</div>
      <p style={{fontSize:12,color:C.muted,marginBottom:12}}>Downloads an encrypted .mmbackup file with profile, profile photo, accounts, goals, insurance details, budgets, recurring schedules, transactions, categories and settings. Safe to save in Google Drive, email to yourself, or WhatsApp. Only you can open it with your PIN.</p>
      <button onClick={async()=>{await exportBackup(data,pin);}} style={SB}>Export full backup (.mmbackup)</button>
    </div>

    {/* Restore */}
    <div style={{background:C.bg,borderRadius:14,padding:16,marginBottom:12}}>
      <div style={{fontSize:14,fontWeight:700,marginBottom:4}}>🔄 Restore from backup</div>
      <p style={{fontSize:12,color:C.muted,marginBottom:12}}>Upload a .mmbackup file and enter the PIN that was used when the backup was created.</p>
      {restoreStep==="idle"&&<>
        <L>Backup file (.mmbackup)</L>
        <input type="file" accept=".mmbackup,.json" style={{...F,padding:8}} onChange={e=>{setRestoreFile(e.target.files[0]||null);setRestoreErr("");}}/>
        <L>PIN used when backup was created</L>
        <input style={F} type="password" value={restorePin} onChange={e=>setRestorePin(e.target.value)} placeholder="Your PIN"/>
        {restoreErr&&<p style={{fontSize:13,color:C.expense,fontWeight:500}}>{restoreErr}</p>}
        <button onClick={doRestore} disabled={!restoreFile||!restorePin} style={{...SB,background:restoreFile&&restorePin?C.brand:"#ccc"}}>Restore</button>
      </>}
      {restoreStep==="done"&&<div style={{color:C.brand,fontWeight:600,fontSize:13}}>{restoreMsg}</div>}
    </div>

    {/* Tax Summary shortcut */}
    <div style={{background:C.bg,borderRadius:14,padding:16}}>
      <div style={{fontSize:14,fontWeight:700,marginBottom:4}}>📊 FY {fy}-{fy+1} Summary</div>
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8,marginTop:10}}>
        <div style={{background:"#E6FBF5",borderRadius:10,padding:10}}><div style={{fontSize:11,color:C.muted}}>Income</div><div style={{fontFamily:"Georgia,serif",fontSize:18,fontWeight:700,color:C.income}}>{inr(fyInc)}</div></div>
        <div style={{background:"#FFEEEE",borderRadius:10,padding:10}}><div style={{fontSize:11,color:C.muted}}>Expense</div><div style={{fontFamily:"Georgia,serif",fontSize:18,fontWeight:700,color:C.expense}}>{inr(fyExp)}</div></div>
      </div>
      <div style={{fontSize:12,color:C.muted,marginTop:8}}>Net savings: <b style={{color:(fyInc-fyExp)>=0?C.brand:C.expense}}>{inr(fyInc-fyExp)}</b> · See full breakdown in the Insights tab.</div>
    </div>
  </Sheet>);
}

/* PDF Import */
function ImportModal({close,data,importBatch,expCats,incCats}){
  const[step,setStep]=useState("pick");const[file,setFile]=useState(null);const[pwd,setPwd]=useState("");const[needPwd,setNP]=useState(false);
  const[accId,setAId]=useState(data.accounts.filter(a=>a.type!=="Loan")[0]?.id||"");
  const[rows,setRows]=useState([]);const[err,setErr]=useState("");const[res,setRes]=useState(null);const[profile,setProfile]=useState(null);const[summary,setSummary]=useState(null);
  const[importReport,setImportReport]=useState(null);const[finalRecon,setFinalRecon]=useState(null);
  const[skipped,setSkipped]=useState([]);const[showSkipped,setShowSkipped]=useState(false);
  const[carryoverDate,setCOD]=useState("");const[carryoverAmt,setCOA]=useState("");const[showCarryover,setSC]=useState(false);
  const nonLoan=data.accounts.filter(a=>a.type!=="Loan");
  const parse=async()=>{if(!file)return;setErr("");setStep("parsing");
    try{const lib=await loadPdf(),buf=await file.arrayBuffer();let pdf;
      try{pdf=await lib.getDocument({data:buf,password:pwd||undefined}).promise;}
      catch(e){if(e&&(e.name==="PasswordException"||/password/i.test(e.message||""))){setNP(true);setErr(pwd?"Wrong password — try again.":"PDF is password-protected. I tried the filename password if available. Please check or edit the password.");setStep("pick");return;}throw e;}
      const pagesTotal=pdf.numPages||0;let readMode="PDF text";
      const rawLines=await extractLines(pdf);let rawLineCount=rawLines.length;let blob=rawLines.join(" ");
      let lines=mergeStatementTransactionLines(rawLines);
      if(!lines.length||lines.length<Math.max(3,Math.floor(rawLines.length*0.12)))lines=rawLines;
      let prof=detectStatementProfile(lines,file.name);setProfile(prof);
      let hit=data.accounts.find(a=>(prof.accountLast4&&a.hint&&a.hint.endsWith(prof.accountLast4))||(a.hint&&a.hint.length>=4&&new RegExp(`${a.hint}\b`).test(blob)));if(hit)setAId(hit.id);
      let parsed=[];let textParseError=null;readMode="PDF text + date-merge";
      try{parsed=parseStatement(lines,data.accounts,data.recurring);}
      catch(e){textParseError=e;}
      if(!parsed.length&&lines!==rawLines){
        try{parsed=parseStatement(rawLines,data.accounts,data.recurring);readMode="PDF text";}
        catch(e){textParseError=e;}
      }
      setProfile({...prof,mode:readMode});
      if(!parsed.length){setErr("Could not confidently read transactions from embedded PDF text. Try an unlocked PDF, split the statement into smaller date ranges, or use CSV/Excel export if available. OCR is disabled because these statements contain embedded text.");setStep("pick");return;}
      const targetAcc=hit?.id||accId;
      const serialStats=extractStatementSerials(lines);
      const audit=balanceAuditRows(parsed);
      const closing=statementClosingCandidate(parsed,rawLines,prof);
      const existingKeys=new Set(data.transactions.map(t=>importDupKey(t.accountId,{...t,desc:t.note})));
      const preparedRows=parsed.map((r,idx)=>{const type=r.isXfer?"transfer":r.type;const pair=findTransferPair({...r,type},targetAcc,data);return {...r,type,rawType:r.type,category:type==="transfer"?"Transfer":mainCategory(r.category),subcategory:r.subcategory||firstSub(mainCategory(r.category),type),duplicate:existingKeys.has(importDupKey(targetAcc,{...r,type})),balanceIssue:audit.bad?.has(idx),transferPair:pair?{accountId:pair.accountId,date:pair.date,amount:pair.amount,level:"opposite",reason:"Matching opposite entry found in another account"}:null};});
      const withXfer=verifyImportRows(preparedRows,targetAcc,data);
      const sum=summarizeImportRows(withXfer);
      const skippedRows=skippedLineCandidates(lines,withXfer);
      const fp=statementFingerprint(prof,sum,file.name);
      const duplicateStatement=getStatementFps().includes(fp);
      setImportReport({pagesRead:pagesTotal,pagesTotal,rawLineCount,mergedLineCount:lines.length,readMode,serialStats,balanceChecked:audit.checked,balanceIssues:audit.issues,balanceMode:audit.mode,skippedRows,fingerprint:fp,duplicateStatement,statementClosing:closing});
      setRows(withXfer);setSummary(sum);
      const hasExisting=data.transactions.some(t=>t.accountId===targetAcc);
      if(!hasExisting&&withXfer.length>0){const sorted=[...withXfer].sort((a,b)=>a.date.localeCompare(b.date));setCOD(prevDay(sorted[0].date));setSC(true);setStep("carryover");}
      else setStep("review");
    }catch(e){setErr(e.message||"Could not read PDF.");setStep("pick");}};

  const doImport=()=>{
    const verified=verifyImportRows(rows,accId,data);
    const ex=new Set(data.transactions.map(t=>importDupKey(t.accountId,{...t,desc:t.note})));
    const fresh=[],skip=[];
    if(showCarryover&&carryoverAmt&&+carryoverAmt>0)fresh.push({id:uid(),type:"income",amount:+carryoverAmt,category:"Other Income",subcategory:"Adjustment",accountId:accId,date:carryoverDate,note:"Opening balance carryover",source:"carryover"});
    verified.filter(r=>r.include).forEach(r=>{const k=importDupKey(accId,r);const liveDup=findImportDuplicateMatch(r,accId,data)||r.transferAlreadyRecorded;if(ex.has(k)||liveDup){skip.push({...r,reason:liveDup?.reason||"Duplicate detected at final check"});return;}ex.add(k);fresh.push({id:uid(),type:r.type,amount:r.amount,category:r.type==="transfer"?"Transfer":mainCategory(r.category),subcategory:r.type==="transfer"?"":(r.subcategory||firstSub(r.category,r.type)),accountId:accId,toAccountId:r.type==="transfer"?r.xferToId:undefined,date:r.date,note:r.desc,source:"import",recurring:!!r.recurMatch});});
    const recon=statementReconciliation(data,accId,[],importReport?.statementClosing,null,fresh);setFinalRecon(recon);
    importBatch(fresh);if(importReport?.fingerprint)saveStatementFp(importReport.fingerprint);setSkipped([...(importReport?.skippedRows||[]),...skip]);setRes({added:fresh.length-(showCarryover&&carryoverAmt&&+carryoverAmt>0?1:0),skipped:skip.length+verified.filter(r=>!r.include&&(r.duplicate||r.transferAlreadyRecorded||r.possibleDuplicate)).length+(importReport?.skippedRows?.length||0),carryover:showCarryover&&+carryoverAmt>0,reconciliation:recon});setStep("done");
  };
  const toggle=k=>setRows(rows.map(r=>r.key===k?{...r,include:!r.include}:r));
  const setType=k=>t=>setRows(verifyImportRows(rows.map(r=>{if(r.key!==k)return r;return {...r,type:t,category:t==="transfer"?"Transfer":(t==="income"?"Salary":"Other"),subcategory:t==="transfer"?"":firstSub(t==="income"?"Salary":"Other",t)};}),accId,data));
  const setCat=k=>c=>setRows(rows.map(r=>{if(r.key!==k)return r;const nr={...r,category:c,subcategory:firstSub(c,r.type)};return {...nr,confidence:rowConfidence(nr)};}));
  const setXferTo=k=>id=>setRows(verifyImportRows(rows.map(r=>r.key===k?{...r,xferToId:id}:r),accId,data));
  const included=rows.filter(r=>r.include).length;
  const liveRecon=statementReconciliation(data,accId,rows,importReport?.statementClosing,{enabled:showCarryover,amount:carryoverAmt,date:carryoverDate});

  return(<Sheet close={close} title="Import Statement">
    {step==="pick"&&<>
      <p style={{fontSize:13,color:C.muted,marginTop:0}}>Pick a bank e-statement PDF. Parsed on your device — nothing uploaded.</p>
      <L>PDF file</L><input type="file" accept="application/pdf" style={{...F,padding:8}} onChange={e=>{const f=e.target.files[0]||null;setFile(f);setErr("");if(f&&!pwd){const g=guessPdfPasswordFromName(f.name);if(g)setPwd(g);}}}/>
      {needPwd&&<><L>PDF password</L><input style={F} type="password" value={pwd} onChange={e=>setPwd(e.target.value)} placeholder="HDFC: first 4 letters of name + DOB in DDMM (e.g. ARPA0408)"/><p style={{fontSize:11,color:C.muted,marginTop:-8}}>You may paste the statement password here. For your test files, the password can be kept in the filename and will be auto-filled locally.</p></>}
      <L>Import into account</L><select style={F} value={accId} onChange={e=>setAId(e.target.value)}>{nonLoan.map(a=><option key={a.id} value={a.id}>{a.name}{a.hint?` ··${a.hint}`:""}</option>)}</select>
      {err&&<p style={{fontSize:13,color:C.expense,fontWeight:500,whiteSpace:"pre-wrap"}}>{err}</p>}
      <button onClick={parse} disabled={!file} style={{...SB,background:file?C.brand:"#ccc",cursor:file?"pointer":"default"}}>Read Statement</button>
    </>}
    {step==="parsing"&&<p style={{textAlign:"center",color:C.muted,padding:"32px 0"}}>Reading your statement…</p>}
    {step==="carryover"&&<>
      <div style={{background:"#EEF3FF",borderRadius:14,padding:16,marginBottom:16,border:"1px solid #C7D7FF"}}><div style={{fontSize:13,fontWeight:700,color:C.xfer,marginBottom:6}}>📌 First statement for this account</div><div style={{fontSize:13,color:C.ink}}>Statement starts from {rows.length>0?[...rows].sort((a,b)=>a.date.localeCompare(b.date))[0].date:""}. Enter your balance on <b>{carryoverDate}</b> to set the correct opening balance.</div></div>
      <L>Account balance on {carryoverDate} (₹)</L>
      <input autoFocus style={F} type="number" value={carryoverAmt} onChange={e=>setCOA(e.target.value)} placeholder="0 if unknown"/>
      <p style={{fontSize:12,color:C.muted,marginTop:-8}}>Creates a one-time opening balance entry. Skip if unsure.</p>
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
        <button onClick={()=>{setSC(false);setCOA("");setStep("review");}} style={{padding:"12px 0",borderRadius:12,border:`1px solid ${C.border}`,background:C.bg,color:C.muted,fontWeight:700,fontSize:14,cursor:"pointer"}}>Skip</button>
        <button onClick={()=>setStep("review")} style={{...SB,margin:0}}>Continue</button>
      </div>
    </>}
    {step==="review"&&<>
      <div style={{background:C.bg,border:`1px solid ${C.border}`,borderRadius:14,padding:12,marginBottom:12}}>
        <div style={{fontSize:12,fontWeight:900,color:C.ink,marginBottom:6}}>Statement check</div>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8,fontSize:11,color:C.muted}}>
          <div><b style={{color:C.ink}}>Bank:</b> {profile?.bank||"Detected"}</div>
          <div><b style={{color:C.ink}}>Rows:</b> {summary?.count||rows.length}</div>
          <div><b style={{color:C.ink}}>Debits:</b> {inr(summary?.debit||0)}</div>
          <div><b style={{color:C.ink}}>Credits:</b> {inr(summary?.credit||0)}</div>
          <div><b style={{color:C.ink}}>Duplicates:</b> {summary?.duplicates||0}</div>
          <div><b style={{color:C.ink}}>Possible:</b> {summary?.possibleDuplicates||0}</div>
          <div><b style={{color:C.ink}}>Review:</b> {summary?.review||0}</div>
          <div><b style={{color:C.ink}}>Own transfers:</b> {summary?.transferPairs||0}</div>
          <div><b style={{color:C.ink}}>Pages:</b> {importReport?`${importReport.pagesRead}/${importReport.pagesTotal}`:"—"}</div>
          <div><b style={{color:C.ink}}>Mode:</b> {importReport?.readMode||profile?.mode||"PDF text"}</div>
          <div><b style={{color:C.ink}}>Balance:</b> {importReport?`${importReport.balanceIssues||0}/${importReport.balanceChecked||0} issues`:"—"}</div>
          <div><b style={{color:C.ink}}>Closing:</b> {liveRecon?(liveRecon.ok?"Matched":"Mismatch"):"—"}</div>
          <div><b style={{color:C.ink}}>Skipped:</b> {importReport?.skippedRows?.length||0}</div>
        </div>
        {profile?.period&&<div style={{fontSize:11,color:C.muted,marginTop:6}}>Period: {profile.period}</div>}
        {importReport?.serialStats?.max>0&&<div style={{fontSize:11,color:C.muted,marginTop:6}}>Statement row numbers detected: {importReport.serialStats.found} / up to {importReport.serialStats.max}{importReport.serialStats.missing?.length?` · Missing serials: ${importReport.serialStats.missing.slice(0,8).join(", ")}${importReport.serialStats.missing.length>8?"…":""}`:""}</div>}
        {importReport?.duplicateStatement&&<div style={{fontSize:11,color:C.expense,marginTop:6,fontWeight:900}}>⚠️ This looks like a statement already imported earlier. Import only after checking duplicates.</div>}
        {profile?.mode&&<div style={{fontSize:11,color:C.warn,marginTop:6}}>Read mode: {profile.mode} — review carefully before import.</div>}
        <div style={{fontSize:11,color:C.muted,marginTop:6}}>Verification: exact duplicates, possible duplicates, already-recorded transfers and balance-problem rows are unticked automatically. Tick only after checking.</div>
      </div>
      {liveRecon&&<div style={{background:liveRecon.ok?C.softIncome:C.softExpense,border:`1px solid ${liveRecon.ok?C.income:C.expense}`,borderRadius:14,padding:12,marginBottom:12}}>
        <div style={{fontSize:12,fontWeight:950,color:liveRecon.ok?C.income:C.expense,marginBottom:6}}>Statement balance reconciliation: {liveRecon.ok?"Matched":"Mismatch"}</div>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8,fontSize:11,color:C.muted}}>
          <div><b style={{color:C.ink}}>Statement closing</b><br/>{inr(liveRecon.statementBalance)}</div>
          <div><b style={{color:C.ink}}>App after import</b><br/>{inr(liveRecon.projectedBalance)}</div>
          <div><b style={{color:C.ink}}>Date</b><br/>{liveRecon.date}</div>
          <div><b style={{color:C.ink}}>Difference</b><br/>{inr(liveRecon.difference)}</div>
        </div>
        {!liveRecon.ok&&<div style={{fontSize:11,color:C.expense,fontWeight:850,marginTop:7}}>This means one or more rows may still be missing, duplicated, wrongly marked as transfer, or excluded. Review before importing.</div>}
      </div>}
      <L>Account</L><select style={F} value={accId} onChange={e=>{const id=e.target.value;setAId(id);const refreshed=verifyImportRows(rows,id,data);setRows(refreshed);setSummary(summarizeImportRows(refreshed));}}>{nonLoan.map(a=><option key={a.id} value={a.id}>{a.name}</option>)}</select>
      <div style={{display:"grid",gap:8,maxHeight:"44vh",overflowY:"auto"}}>
        {rows.map(r=>(<div key={r.key} style={{border:`1px solid ${C.border}`,borderRadius:12,padding:"10px 12px",opacity:r.include?1:0.4}}>
          <div style={{display:"flex",alignItems:"center",gap:10}}>
            <input type="checkbox" checked={r.include} onChange={()=>toggle(r.key)} style={{width:18,height:18,accentColor:C.brand,flexShrink:0}}/>
            <div style={{flex:1,minWidth:0}}>
              <div style={{fontSize:12,fontWeight:600,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{r.recurMatch&&<span style={{color:C.brand}}>🔁 </span>}{r.isXfer&&!r.recurMatch&&<span style={{color:C.xfer}}>⚡ </span>}{r.desc||"(no description)"}{r.recurMatch&&<span style={{fontSize:10,color:C.brand}}> · "{r.recurMatch.name}"</span>}</div>
              <div style={{fontSize:10,color:C.muted}}>{new Date(r.date).toLocaleDateString("en-IN",{day:"numeric",month:"short",year:"numeric"})}</div>
            </div>
            <span style={{fontFamily:"Inter,system-ui,sans-serif",fontSize:13,fontWeight:900,color:r.type==="income"?C.income:r.type==="transfer"?C.xfer:C.expense,flexShrink:0}}>{r.type==="income"?"+":r.type==="transfer"?"↔":"−"}{inr(r.amount)}</span>
          </div>
          {r.confidence&&<div style={{display:"inline-flex",alignItems:"center",marginTop:7,padding:"3px 8px",borderRadius:999,background:r.confidence.bg,color:r.confidence.tone,fontSize:10,fontWeight:900}}>{r.confidence.label}</div>}
          {r.duplicateMatch&&<div style={{fontSize:10.5,color:r.duplicateMatch.level==="possible"?C.warn:C.muted,marginTop:5,fontWeight:800}}>{r.duplicateMatch.reason}</div>}
          {r.transferPair&&<div style={{fontSize:10.5,color:C.xfer,marginTop:5,fontWeight:800}}>{r.transferPair.reason||"Matched similar entry in another account"} on {r.transferPair.date}. Check if this should be a transfer.</div>}
          {r.balanceIssue&&<div style={{fontSize:10.5,color:C.expense,marginTop:5,fontWeight:800}}>Balance reconciliation did not match for this row.</div>}
          {r.include&&<div style={{display:"grid",gap:4,marginTop:8}}>
            <div style={{display:"flex",gap:6}}>
              <select value={r.type} onChange={e=>setType(r.key)(e.target.value)} style={{...F,marginBottom:0,padding:"5px 8px",fontSize:11,flex:1}}><option value="expense">Expense</option><option value="income">Income</option><option value="transfer">Transfer</option></select>
              {r.type!=="transfer"&&<select value={r.category} onChange={e=>setCat(r.key)(e.target.value)} style={{...F,marginBottom:0,padding:"5px 8px",fontSize:11,flex:2}}>{(r.type==="income"?incCats:expCats).map(c=><option key={c}>{c}</option>)}</select>}
            </div>
            {r.type==="transfer"&&<select value={r.xferToId||""} onChange={e=>setXferTo(r.key)(e.target.value)} style={{...F,marginBottom:0,padding:"5px 8px",fontSize:11}}><option value="">— Select destination —</option>{data.accounts.map(a=><option key={a.id} value={a.id}>{a.name}</option>)}</select>}
          </div>}
        </div>))}
      </div>
      <button onClick={doImport} disabled={!included} style={{...SB,marginTop:12,background:included?C.brand:"#ccc",cursor:included?"pointer":"default",position:"sticky",bottom:0}}>Import {included}</button>
    </>}
    {step==="done"&&res&&<div style={{textAlign:"center",padding:"20px 0"}}>
      <div style={{fontSize:44,marginBottom:12}}>✅</div>
      {res.carryover&&<div style={{background:C.brandDim,border:`1px solid ${C.brand}`,borderRadius:10,padding:10,marginBottom:12,fontSize:13,color:C.brand}}>Opening balance carryover added ✓</div>}
      <div style={{fontSize:16,fontWeight:700,color:C.ink}}>{res.added} transaction{res.added===1?"":"s"} imported</div>
      {(res.reconciliation||finalRecon)&&<div style={{margin:"12px 0",background:(res.reconciliation||finalRecon).ok?C.softIncome:C.softExpense,border:`1px solid ${(res.reconciliation||finalRecon).ok?C.income:C.expense}`,borderRadius:12,padding:10,fontSize:12,color:C.ink,textAlign:"left"}}>
        <b style={{color:(res.reconciliation||finalRecon).ok?C.income:C.expense}}>Closing balance {(res.reconciliation||finalRecon).ok?"matched":"mismatch"}</b><br/>
        Statement: {inr((res.reconciliation||finalRecon).statementBalance)} · App: {inr((res.reconciliation||finalRecon).projectedBalance)} · Difference: {inr((res.reconciliation||finalRecon).difference)}
      </div>}
      {res.skipped>0&&<div style={{fontSize:13,color:C.muted,marginTop:6}}>{res.skipped} duplicate{res.skipped===1?"":"s"} skipped</div>}
      {skipped.length>0&&<button onClick={()=>setShowSkipped(!showSkipped)} style={{background:"none",border:`1px solid ${C.border}`,borderRadius:8,padding:"6px 14px",fontSize:12,color:C.muted,cursor:"pointer",marginTop:8}}>{showSkipped?"Hide":"View"} skipped</button>}
      {showSkipped&&<div style={{textAlign:"left",marginTop:10,display:"grid",gap:6,maxHeight:"25vh",overflowY:"auto"}}>{skipped.map((r,i)=><div key={i} style={{background:C.bg,borderRadius:8,padding:"8px 10px",fontSize:11}}><div style={{fontWeight:700,color:C.muted}}>{r.desc||r.line||"Skipped row"}</div><div style={{color:C.muted}}>{r.reason?`${r.reason} · `:""}{r.date||""}{r.amount?` · ${inr(r.amount)}`:""}</div></div>)}</div>}
      <button onClick={close} style={{...SB,marginTop:12}}>Done</button>
    </div>}
  </Sheet>);
}

/* ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
   SHARED PRIMITIVES
   ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━ */
function Sheet({children,close,title}){return(<div onClick={close} style={{position:"fixed",inset:0,background:"rgba(10,20,30,0.6)",display:"flex",alignItems:"flex-end",justifyContent:"center",zIndex:50}}><div onClick={e=>e.stopPropagation()} style={{background:C.card,borderRadius:"20px 20px 0 0",width:"100%",maxWidth:560,padding:"20px 20px calc(20px + env(safe-area-inset-bottom))",maxHeight:"90vh",overflowY:"auto"}}>{title&&<div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:18}}><h2 style={{fontSize:18,fontWeight:800,margin:0,color:C.ink}}>{title}</h2><button onClick={close} style={{background:"none",border:"none",color:C.muted,cursor:"pointer",padding:4}}><X size={20}/></button></div>}{children}</div></div>);}
function Card({children}){return <div style={{margin:"16px 16px 0",background:C.card,borderRadius:16,padding:16,boxShadow:"0 2px 12px rgba(0,0,0,0.06)"}}>{children}</div>;}
function Nbtn({children,onClick}){return <button onClick={onClick} style={{background:"rgba(255,255,255,0.1)",border:"none",color:"#fff",width:30,height:30,borderRadius:8,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center"}}>{children}</button>;}
function Pbtn({children,onClick,style}){return <button onClick={onClick} style={{display:"inline-flex",alignItems:"center",gap:4,padding:"8px 12px",borderRadius:12,border:"none",background:C.brand,color:"#fff",fontSize:12,fontWeight:700,cursor:"pointer",...style}}>{children}</button>;}
function Pill({children,onClick}){return <button onClick={onClick} style={{display:"inline-flex",alignItems:"center",gap:5,padding:"6px 12px",borderRadius:20,border:`1px solid ${C.border}`,background:C.card,color:C.muted,fontSize:12,fontWeight:600,cursor:"pointer"}}>{children}</button>;}
function Eye({children,style}){return <div style={{fontSize:11,fontWeight:700,color:C.muted,letterSpacing:"0.08em",textTransform:"uppercase",marginBottom:8,...style}}>{children}</div>;}
const SoftRoundBtn={background:C.card,border:`1px solid ${C.border}`,color:C.muted,width:34,height:34,borderRadius:12,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",boxShadow:"0 2px 8px rgba(13,27,42,0.05)"};
const PeriodBtn={padding:"12px 10px",borderRadius:14,border:`1px solid ${C.border}`,background:C.card,color:C.ink,fontSize:13,fontWeight:800,cursor:"pointer"};
const H2 ={fontSize:20,fontWeight:800,margin:0};
const IBN={background:"none",border:"none",color:"#BCC5CF",cursor:"pointer",padding:4};
const F  ={width:"100%",border:`1px solid ${C.border}`,borderRadius:10,padding:"10px 12px",fontSize:13,color:C.ink,background:"#FAFAFA",marginBottom:12};
const L  =({children})=><div style={{fontSize:11,fontWeight:700,color:C.muted,marginBottom:5,letterSpacing:"0.06em",textTransform:"uppercase"}}>{children}</div>;
const SB ={width:"100%",background:C.brand,border:"none",borderRadius:12,padding:"12px 0",color:"#fff",fontSize:14,fontWeight:700,cursor:"pointer",marginTop:4};
